<script type="text/javascript">

// #region CommPortal Specific

function addLoanOfficerToolTip(version = "") {
	const loName = "{{user.lv_loanofficer.name}}";
	const tip = loName == null || loName.length <= 2 ? "No Officer" : loName;
	const $eUserName = $("span.username:first");
	$eUserName.attr('title', tip + version);
}

function addRolesToolTip() {
	const $navbar = $('body > div.navbar-expand-xl.navbar.navbar-dark.static-top');

  if ($navbar.length) {
    $('<span>')
      .css({
        position: 'absolute',
        width: '10px',
        height: '10px',
        top: '10px',
        right: '10px',
        display: 'block',
        cursor: 'default'
      })
      .attr('title', '! todo8 need roles here')
      .appendTo($navbar.css('position', 'relative'));

    //console.log('special added');
  } else {
    console.error('Navbar not found!');
  }}

// MIGRATED TO LVGlobal.js: formatApprovalDate() and formatPersonalizedApprovalMessage()


// #endregion CommPortal Specific

// #region Init
window.G_Verbose = true; // aabbcc

// Initialize G_Tags based on query string parameter "tags" and localStorage "debugtags"
window.G_Tags = (function() {
	const urlParams = new URLSearchParams(window.location.search);
	const tagsParam = urlParams.get('tags') || '';

	// Get debug tags from localStorage
	const localStorageTags = localStorage.getItem('tags') || '';

	// Create set of debug tags from CSV parameter and localStorage
	const tagSet = new Set();

	// Add tags from query string parameter
	if (tagsParam.trim()) {
		tagsParam.split(',').forEach(tag => {
			const trimmedTag = tag.trim();
			if (trimmedTag) {
				tagSet.add(trimmedTag.toLowerCase());
			}
		});
	}

	// Append tags from localStorage
	if (localStorageTags.trim()) {
		localStorageTags.split(',').forEach(tag => {
			const trimmedTag = tag.trim();
			if (trimmedTag) {
				tagSet.add(trimmedTag.toLowerCase());
			}
		});
	}

	return {
		Has: function(tag) {
			return tagSet.has(tag.toLowerCase());
		},
		List: function() {
			return Array.from(tagSet);
		},
		Size: function() {
			return tagSet.size;
		}
	};
})();

// Initialize Playwright automation flag - pages can set this to true when ready
window.playwrightReady = false;

let CSRF_TOKEN = 'set in js';
const SPIN_CONT_ID = 'global-spinner-container';
const SPIN_ELEM_ID = 'global-spinner-elem';

if (typeof window.PAGE_USERID === 'undefined') {
	console.log("Footer: setting globals because not defined")
	window.PAGE_USERID = "{{user.id}}";
	window.PAGE_USEREMAIL = "{{user.emailaddress1}}";
	window.PAGE_USERNAME = "{{user.fullname}}";
} else {	
	console.log("Footer: NOT setting globals because ALREADY defined");
}

// Admin Recovery variables are now set by SetupQuery instead of Footer
// This ensures they have access to the web roles query results

// Log page visits when the DOM is ready
document.addEventListener('DOMContentLoaded', async function() {
	console.log("ENTER>> BASE DOMContent Loaded");

	const response = await fetch('/_layout/tokenhtml');
	const html = await response.text();
	const parser = new DOMParser();
	const doc = parser.parseFromString(html, 'text/html');
	CSRF_TOKEN = doc.querySelector('input[name="__RequestVerificationToken"]').value;

	// hideNavLinks(); // Removed - navigation handled by Liquid templates

	initPersistentControls();

	// The timeout is not really necessary, but leaving it
	setTimeout(function() {
		//restoreSelectedPeriod();
		//restoreSelectedBranch();
		logPageVisit();
		addRolesToolTip();
		addLoanOfficerToolTip();
	}, 3000);

	// CRITICAL: Dispatch LVGlobalDOCReady after short delay to ensure:
	// 1. DOM is fully loaded
	// 2. CSRF token is available
	// 3. All utility functions are defined (BeginsWith, Has, Is, etc.)
	// 4. All inline page scripts have been parsed and listeners attached
	setTimeout(function() {
		document.dispatchEvent(new CustomEvent("LVGlobalDOCReady"));
		console.log("FOOTER: LVGlobalDOCReady event dispatched - all functions loaded");
	}, 100);

	console.log("<<LEAVE BASE DOMContent Loaded");
});

function hideNavLinks() {
    // Navigation visibility is now handled entirely by the Liquid templates in Header.webtemplate
    // This ensures admin users see everything regardless of specific role assignments
    // Removed the old JavaScript-based hiding logic that was conflicting with our Liquid template approach
}

function restoreSelectedPeriod() {
	console.log("ENTER: restore selected period");

	const periodSelect = document.getElementById('period-select');

	if (!periodSelect) {
		console.log("LEAVE: restore selected period, periodSelect not found");
		return;
	}

	// Try to get the saved period from local storage
	const savedPeriod = localStorage.getItem('selectedPeriod');

	// If no saved period, exit the function
	if (!savedPeriod) {
		console.log("LEAVE: restore selected period, nothing found in local storage");
		return;
	}

	// Check if there's an option with the saved value
	const optionExists = Array.from(periodSelect.options).some(option => option.value === savedPeriod);

	// Only set the value if a matching option exists
	if (optionExists) {
		console.log("found value in local storage, and it DOES does exist.")
		periodSelect.value = savedPeriod;

		// Optionally trigger a change event if needed
		//const event = new Event('change');
		//periodSelect.dispatchEvent(event);
	} else {
		console.log("found value in local storage, but does not exist.")
	}
}

function restoreSelectedBranch() {
	console.log("ENTER: restore selected branch");

	const branchSelect = document.getElementById('branch-select');

	if (!branchSelect) {
		console.log("LEAVE: restore selected branch, branchSelect not found");
		return;
	}

	// Try to get the saved period from local storage
	const savedBranch = localStorage.getItem('selectedBranch');

	// If no saved branch, exit the function
	if (!savedBranch) {
		console.log("LEAVE: restore selected branch, nothing found in local storage");
		return;
	}

	// Check if there's an option with the saved value
	const optionExists = Array.from(branchSelect.options).some(option => option.value === savedBranch);

	// Only set the value if a matching option exists
	if (optionExists) {
		console.log("found branch value in local storage, and it DOES does exist.")
		branchSelect.value = savedBranch;

		// Optionally trigger a change event if needed
		//const event = new Event('change');
		//periodSelect.dispatchEvent(event);
	} else {
		console.log("found branch value in local storage, but does not exist.")
	}
}
// #endregion Init

// #region Logging

// MIGRATED TO LVGlobal.js: getFirstPathSegment()

function logPageVisit() {
	try {
		/*
		const pageData = {
			path: window.location.pathname,
			userAgent: navigator.userAgent
		};

		if (window.Microsoft && window.Microsoft.Dynamic365 && window.Microsoft.Dynamic365.Portal &&
			window.Microsoft.Dynamic365.Portal.User) {
			pageData.userId = window.Microsoft.Dynamic365.Portal.User.contactId;
			pageData.userName = window.Microsoft.Dynamic365.Portal.User.userName;
		}
		*/

		// Get current user ID (set by Footer template from Liquid)
		const currentUser = window.PAGE_USERID;
		const sessionUser = sessionStorage.getItem('signin_user');

		// If user is not authenticated, clear the session storage
		if (!currentUser || currentUser === "" || currentUser === "undefined") {
			sessionStorage.removeItem('signin_user');
			sessionStorage.removeItem('signin_logged');
			return; // Don't log anything for unauthenticated users
		}

		// Check if this is a new signin (user changed or first signin in this session)
		if (currentUser !== sessionUser) {
			// New user signin detected - log it with user agent information
			const userAgentData = {
				userAgent: navigator.userAgent,
				platform: navigator.platform,
				vendor: navigator.vendor
			};
			writeToLogTable('SignIn', window.location.pathname, '', '', '', '', userAgentData);

			// Store this user as the current session user
			sessionStorage.setItem('signin_user', currentUser);
			sessionStorage.setItem('signin_logged', 'true');

			console.log('SignIn detected - User: ' + currentUser + ' (previous: ' + (sessionUser || 'none') + ')');
		}

		// Always log the regular page visit
		writeToLogTable('PageVisit', window.location.pathname + window.location.search);
	} catch (error) {
		console.error('Error logging page visit:', error);
	}
}

async function logCount(kind = null, key1Name = null, key1Value = null, key2Name = null, key2Value = null) {
	// Uggh: never could figure out how to get a simple count to work when using a filter,
	// so I restored to this ridiculs approach of extracting the @odata.count value from a single returned record.
	let filterParts = [];

	// Add each filter condition if the parameter is provided
	if (kind !== null) {
		filterParts.push(`lv_kind eq '${encodeURIComponent(kind)}'`);
	}

	if (key1Name !== null) {
		filterParts.push(`lv_key1name eq '${encodeURIComponent(key1Name)}'`);
	}

	if (key1Value !== null) {
		filterParts.push(`lv_key1value eq '${encodeURIComponent(key1Value)}'`);
	}

	if (key2Name !== null) {
		filterParts.push(`lv_key2name eq '${encodeURIComponent(key2Name)}'`);
	}

	if (key2Value !== null) {
		filterParts.push(`lv_key2value eq '${encodeURIComponent(key2Value)}'`);
	}

	// Join filter parts with 'and'
	const filterQuery = filterParts.length > 0 ? `$filter=${filterParts.join(' and ')}` : '';

	// Use $count=true and minimize data with $top=1
	const apiUrl = `/_api/lv_logs?${filterQuery}${filterQuery ? '&' : ''}$count=true&$top=1`;

	console.count("logCount: url=" + apiUrl);

	try {
		const result = await apiCall(apiUrl, 'GET');

		if (result.success) {
			// Extract count from @odata.count metadata
			if (result.data && result.data["@odata.count"] !== undefined) {
				return parseInt(result.data["@odata.count"], 10);
			} else {
				console.warn('Count metadata not found in response:', result);
				return 0;
			}
		} else {
			console.error('API call failed when counting logs:', result.message);
			return 0;
		}
	} catch (error) {
		console.error('Error counting log entries:', error);
		return 0;
	}
}

async function apiCount(apiUrl) { // expects a url that includes $count=true
	if (!apiUrl.Has("count=true"))
		throw "apiCount: expected a url with count=true todo8: autohandle whether it is there or not";

	try {
		console.log("apiCount: url=" + apiUrl);
		const result = await apiCall(apiUrl, 'GET');

		if (result.success) {
			// Extract count from @odata.count metadata
			if (result.data && result.data["@odata.count"] !== undefined) {
				return parseInt(result.data["@odata.count"], 10);
			} else {
				console.warn('apiCount: Count metadata not found in response:', result);
				return -1;
			}
		} else {
			console.error('apiCount: API call failed when counting:', result.message);
			return -2;
		}
	} catch (error) {
		console.error('apiCount: Error counting:', error);
		return -3;
	}
}

async function logSelect(sname, oSel) { // Called from various dropdown choices: period selection, branch selection
	writeToLogTable('Select:' + sname, oSel.text, "text", oSel.text, "value", oSel.value);
}

async function logWrite(logKind, logDetail, k1name = "", k1val = "", k2name = "", k2val = "", logData=null, waitForCompletion = false) {
	writeToLogTable(logKind, logDetail, k1name, k1val, k2name, k2val, logData, waitForCompletion);
}

async function writeToLogTable(logKind, logDetail, k1name = "", k1val = "", k2name = "", k2val = "", logData=null, waitForCompletion = false) { // by default is async
	// Example of how to await
	//    const result = await writeToLogTable("ERROR", "Something critical", null, true);
	//    if (result.success)
	//       console.log('no problem');
	//    else {
	//       console.error(whatever)
	//       do whatever you need to do
	//    }

	var postData = {
		lv_kind: logKind,
		lv_detail: logDetail,
		lv_userid: "{{ user.id }}",
		lv_userfullname: "{{ user.fullname }}",
		lv_key1name: k1name,
		lv_key1value: k1val,
		lv_key2name: k2name,
		lv_key2value: k2val
	};

	if (HasValue(logData)) {
		if (typeof logData === 'object') {
			postData.lv_memo = JSON.stringify(logData);
		} else {
			postData.lv_memo = logData;
		}
	}

	const sbody = JSON.stringify(postData);

	dbglog('writeToLogTable: logKind=' + logKind + '; logDetail=' + logDetail + '; csrf=' + CSRF_TOKEN.substring(0,5) + '; sbody=' + sbody);

	const fetchPromise = fetch('/_api/lv_logs', {
		method: 'POST',
		headers: {
			'Content-Type': 'application/json',
			'__RequestVerificationToken': CSRF_TOKEN
		},
		body: sbody
	})
	.then(async response => {
		if (!response.ok) {
            const errorText = await response.text();
            console.error(`Error response ${response.status}:`, errorText);
            return Promise.reject({ handled: true, status: response.status, text: errorText });
		}
		return response.status === 204 ? {} : response.json();
	})
	.then(data => {
		//console.log('Log entry created:', data);
		console.log("wtlt");
		return { success: true, data: data };
	})
	.catch(error => {
		// Only log if we haven't already handled it
		if (!error.handled) {
			console.log('Error logging entry (rjid=2503140957b)');
		}
		return { success: false, error: error.handled ? 'Request failed' : error.message };
	});

	// If caller wants to wait for completion, return the promise
	if (waitForCompletion) {
		return fetchPromise;
	}

	// Otherwise, fire and forget
	return { success: true, message: "Log operation started" };
}

// #endregion Logging

// #region Email
async function sendEmail(kind, subject, body, to = "", loanOfficerId = "", periodCode = "", loanNo = "", verbose = false, periodNo = -1) {
	console.log(`ENTER: sendEmail: kind=${kind}; subject=${subject}; body=${body}; to=${to}; loanOfficerId=${loanOfficerId}; periodCode=${periodCode}; loanNo=${loanNo}`);

	const oPostEmailLog = {
		"lv_kind": kind,
		"lv_subject": subject,
		"lv_Contact@odata.bind": `/contacts(${window.PAGE_USERID})`,
	};

	if (HasValue(loanOfficerId))
		oPostEmailLog["lv_LoanOfficer@odata.bind"] = `/lv_lvcomploanofficers(${loanOfficerId})`;

	if (HasValue(periodCode))
		oPostEmailLog["lv_periodcode"] = periodCode;

	if (periodNo > -1)
		oPostEmailLog["lv_periodno"] = periodNo;

	// Fails if not string
	loanNo = String(loanNo);
	if (HasValue(loanNo))
		oPostEmailLog["lv_loanno"] = loanNo;

	await apiCall("/_api/lv_lvcompemaillogs", "POST", oPostEmailLog, verbose);
}

// #endregion Email

// #region Dialogs
function askQuestion(qText, btn1Text = "OK", btn2Text = "Cancel") {
    return new Promise((resolve) => {
        const modalId = 'customModal_' + Math.random().toString(36).substr(2, 9);

		const modalHTML = `
			<div class="modal fade" id="${modalId}" tabindex="-1" role="dialog" aria-labelledby="${modalId}Label" aria-hidden="true">
				<div class="modal-dialog modal-dialog-centered" role="document">
					<div class="modal-content">
						<div class="modal-body">
							${qText}
						</div>
						<div class="modal-footer">
							<button type="button" class="btn btn-secondary" id="${modalId}-btn2">${btn2Text}</button>
							<button type="button" class="btn btn-primary" id="${modalId}-btn1">${btn1Text}</button>
						</div>
					</div>
				</div>
			</div>
		`;        

		$('body').append(modalHTML);

        const $modal = $(`#${modalId}`);
        const $btn1 = $(`#${modalId}-btn1`);
        const $btn2 = $(`#${modalId}-btn2`);

        $btn1.on('click', function() {
            $modal.modal('hide');
            resolve(btn1Text);
        });

        $btn2.on('click', function() {
            $modal.modal('hide');
            resolve(btn2Text);
        });

        $modal.on('hidden.bs.modal', function() {
            $modal.remove();
        });

        // Show it
        $modal.modal({
            backdrop: 'static',  // Prevents closing when clicking outside
            keyboard: false      // Prevents closing with keyboard
        });
        $modal.modal('show');
    });
}

// Helper function for easier synchronous-like usage
askQuestion.confirm = async function(message) {
    const result = await askQuestion(message, "Yes", "No");
    return result === "Yes";
};

// HowTo: use helper
/*
async function deleteRecord() {
    if (await askQuestion.confirm("Are you sure you want to delete this record?")) {
        // User confirmed, proceed with deletion
        console.log("Deleting record...");
    } else {
        // User canceled
        console.log("Operation canceled");
    }
}
*/

// #endregion Dialogs

// #region ~Spinner
function spinInit() {
	if (document.getElementById(SPIN_CONT_ID))
		return;

	const spinCont = document.createElement('div');
	spinCont.id = SPIN_CONT_ID;
	spinCont.style.position = 'fixed';
	spinCont.style.top = '50%';
	spinCont.style.left = '50%';
	spinCont.style.transform = 'translate(-50%, -50%)';

	// spinCont.style.backgroundColor = 'rgba(0, 0, 0, 0.5)'; uncomment to darken entire screen. Actually cannot just uncomment, will need other changes related to sizing. But this will be a start

	spinCont.style.display = 'none'; // Hidden by default
	spinCont.style.justifyContent = 'center';
	spinCont.style.alignItems = 'center';
	spinCont.style.zIndex = '10001'; // Higher than other modals

	const spin = document.createElement('div');
	spin.id = SPIN_ELEM_ID;
	spin.style.border = '5px solid #f3f3f3';
	spin.style.borderTop = '5px solid #3498db';
	spin.style.borderRadius = '50%';
	spin.style.width = '50px';
	spin.style.height = '50px';
	spin.style.animation = 'spin 2s linear infinite';

	// Add a small white background circle behind the spinner for better visibility
	spin.style.backgroundColor = '#ffffff';
	spin.style.boxShadow = '0 0 10px rgba(0, 0, 0, 0.1)';
	spin.style.padding = '10px';

	// Add animation style
	const styleElement = document.createElement('style');
	styleElement.textContent = `
		@keyframes spin {
		0% { transform: rotate(0deg); }
		100% { transform: rotate(360deg); }
	}
	`;
	document.head.appendChild(styleElement);

	spinCont.appendChild(spin);

	document.body.appendChild(spinCont);
}

function spinShow(state) {
	// If spin container doesn't exist yet, create it
	if (!document.getElementById(SPIN_CONT_ID))
		spinInit();

	const spinCont = document.getElementById(SPIN_CONT_ID);

	// If state is explicitly provided (true or false)
	if (state === true) {
		spinCont.style.display = 'flex'; // Force visible
	} else if (state === false) {
		spinCont.style.display = 'none'; // Force hidden
	} else {
		// Toggle current state if no state parameter is provided
		spinCont.style.display = 
			spinCont.style.display === 'none' || 
			spinCont.style.display === '' ? 'flex' : 'none';
	}
}

// #endregion Spinner

// #region API and Auth
function handleMsalRedirect() { // For API calls
  // Do we have a redirect response we need to handle?
  msalInstance.handleRedirectPromise()
    .then(response => {
      if (response) {
        console.log("handleMsalRedirect: Handled redirect response", response);
      }
    })
    .catch(error => {
      console.error("handleMsalRedirect: Error handling redirect:", error);
    });
}

function getRedirectUri() {
    const currentUrl = window.location.href;

    if (currentUrl.includes('localhost') || currentUrl.includes('127.0.0.1'))
        return 'http://localhost:5500';

	if (currentUrl.includes('commportaltest.powerappsportals.com'))
        return 'https://commportaltest.powerappsportals.com';

    console.warn('Unknown environment, using current origin as redirect URI');
	return window.location.origin;
}

const msalConfig = {
	auth: {
		clientId: 'faec3f79-f37f-4f50-b93a-9926ca206c53',
		authority: 'https://login.microsoftonline.com/1598698c-cbd2-4d4a-94f0-0b4b2b701763',
		redirectUri: getRedirectUri()
	},
	cache: {
		cacheLocation: "localStorage",
		storeAuthStateInCookie: true
	}
};

// Initialize MSAL
const msalInstance = new msal.PublicClientApplication(msalConfig);

function checkAccount() { // At page load, do we already have cached accounts?
	const currentAccounts = msalInstance.getAllAccounts();
	if (currentAccounts.length > 0) {
		console.log("checkAccount: User is already signed in");
		return currentAccounts[0];
	} else {
		console.log("checkAccount: no existing account found");
		return null;
	}
}

async function getToken() {
    try {
		let account = checkAccount();

        const tokenRequest = {
            scopes: ["https://api.businesscentral.dynamics.com/.default"]
        };

		if (account)
			tokenRequest.account = account;

        try {
            const response = await msalInstance.acquireTokenSilent(tokenRequest);
			console.log("getToken: got it silently");
            return response.accessToken;
        } catch (error) {
            console.log("getToken: silent acquisition did not work, presenting auth dialog to user");
            const response = await msalInstance.acquireTokenPopup(tokenRequest);
            return response.accessToken;
        }
    } catch (error) {
        console.error("getToken(): Authentication failed:", error);
    }
}

function getAntiForgerySafely() {
	const tokenElement = document.querySelector('#tokenForm input[name="__RequestVerificationToken"]');
	if (tokenElement) {
		return tokenElement.value;
	} else {
		console.error("Anti-forgery token not found on page");
		return null;
	}
}

/**
 * Obtains an OAuth token using client credentials flow
 * Similar to the C# ClientSecretCredential implementation
 * @param {string} clientId - The client ID
 * @param {string} clientSecret - The client secret
 * @param {string} tenantId - Optional tenant ID (if not provided, will use 'common')
 * @returns {Promise<string>} - A promise that resolves to the access token
 */
 async function getOAuthToken(clientId, clientSecret, tenantId = "common") { // deprecated now that using MSAL?
  console.log(`Requesting token for ClientId=${clientId}`);

  // The token endpoint (Azure AD token endpoint)
  const tokenUrl = `https://login.microsoftonline.com/${tenantId}/oauth2/v2.0/token`;

  // Create the form data for the token request - note that the C# code uses Azure.Identity's ClientSecretCredential
  // which handles the OAuth flow details internally, but we need to specify them explicitly in JS
  const formData = new URLSearchParams();
  formData.append("grant_type", "client_credentials");
  formData.append("client_id", clientId);
  formData.append("client_secret", clientSecret);
  formData.append("scope", "https://api.businesscentral.dynamics.com/.default");

  // Make the token request
  const response = await fetch(tokenUrl, {
    method: "POST",
    headers: {
      "Content-Type": "application/x-www-form-urlencoded"
    },
    body: formData
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`Failed to get OAuth token: ${response.status} ${response.statusText} - ${errorText}`);
  }

  const data = await response.json();

  if (!data.access_token) {
    throw new Error("No access token received in response");
  }

  console.log(`Token received. First 10 chars: ${data.access_token.substring(0, 10)}`);
  return data.access_token;
}

function parseHeaders(headersText, method) {
	const headerLines = headersText.split('\n');
	const headers = {};

	headerLines.forEach(line => {
		if (line.trim()) {
			const parts = line.split('|');
			if (parts.length === 2) {
				const key = parts[0].trim();
				const value = parts[1].trim();
				headers[key] = value;
			}
		}
	});

	if (method == "GET") {
		console.log('parseHeaders: not adding token cuz GET');
	} else {
		headers["__RequestVerificationToken"] = CSRF_TOKEN;
	}

	return headers;
}

async function apiGetRecords(tableNamePlural, filterExpr = "", topN = 0) { // returns array of record object
	// 	const url = `/_api/lv_lvcompcommissionapprovals?$filter=lv_loanofficercode eq '${window.PAGE_LOID_BEINGVIEWED}' and lv_periodcode eq '${perCode}'&$count=true&$top=1`;

	{% comment %}     // By design, we are NOT verifying that the filter would actually only return one row. Why? I dunno. Don't wannt mess with it?    {% endcomment %}

	if (HasValue(filterExpr)) {
		// Using native startsWith() instead of custom BeginsWith() to avoid timing issues
		// NOTE: startsWith is case-sensitive (unlike BeginsWith which was case-insensitive)
		if (!filterExpr.startsWith("$") && !filterExpr.startsWith("filter")) {
			filterExpr = "$filter=" + filterExpr
		}
	}

	{% comment %}
	Error:  https://commportaltest.powerappsportals.com/_api/lv_lvcompbranchs?&$count=true&$top=1
	GOOD:   https://commportaltest.powerappsportals.com/_api/lv_lvcompbranchs?$count=true&$top=1	
	{% endcomment %} 

	const topExpr = topN > 0 ? "&$top=" + topN : "";

	let url = `/_api/${tableNamePlural}?${filterExpr}&$count=true${topExpr}`;

	//console.log("apiGetRecordS: url 1 =" + url);

	url = url.replace("?&", "?");

	console.log("apiGetRecordS: url 2 =" + url);

	const oResp = await apiCall(url , "GET");

