async function apiGetColumnStringArray(tableNamePlural, columnName, filterExpr) { // returns array of string
	let retArr = [];

	const arrRecs = await apiGetRecords(tableNamePlural, filterExpr)

	if (HasValue(arrRecs) && arrRecs.length > 0) {
		for (let i = 0; i < arrRecs.length; i++) {
			const record = arrRecs[i];

			if (record && record[columnName] !== undefined) {
				retArr.push(String(record[columnName]));
			}
		}
	}

	return retArr;
}

async function apiGetColumnStringScalar(tableNamePlural, columnName, filterExpr) { // returns a single string
	let ret = null;

	const colArray = await apiGetColumnStringArray(tableNamePlural, columnName, filterExpr);

	if (HasValue(colArray) && colArray.length > 0)
		ret = colArray[0];

	return ret;
}

async function apiCall(apiUrl, method, postData = "", verbose = false, headersText = "", clientId = "", clientSecret = "", tenantId = "common") {
    // Used only in devtools debugging
    if (typeof G_Verbose !== 'undefined') {
        verbose = G_Verbose;
    }

	function log(any) {
		if (verbose)
			console.log(any);
	}

	console.log("ENTER: apiCall. apiUrl=" + apiUrl + "; method=" + method + (clientId ? "; Using OAuth authentication" : ""));

	if (method === 'PATCH' && (apiUrl.includes('contacts') || verbose)) {
		console.log('🔍 CONTACT UPDATE DEBUG - apiCall entry');
		console.log('🔍 Full apiUrl:', apiUrl);
		console.log('🔍 Method:', method);
		console.log('🔍 PostData type:', typeof postData);
		console.log('🔍 PostData value:', postData);
		console.log('🔍 Verbose mode:', verbose);
		console.log('🔍 Environment check:', {
			location: window.location.href,
			userAgent: navigator.userAgent.substring(0, 100),
			timestamp: new Date().toISOString()
		});
	}

	if (method === 'POST' && (apiUrl.includes('flow') || (postData && postData.action && (postData.action === 'add' || postData.action === 'remove')))) {
		console.log('🔍 WEB ROLE FLOW DEBUG - apiCall entry');
		console.log('🔍 Flow URL:', apiUrl);
		console.log('🔍 Flow action:', postData.action, 'Contact ID:', postData.contactId, 'Role ID:', postData.roleId);
		console.log('🔍 Full POST data:', postData);
	}

	apiUrl = normalizeUrl(apiUrl);

    const headers = parseHeaders(method, headersText);

    const timestamp = new Date().toISOString();

    let requestInfo = `API Call at ${timestamp}\n`;

    const options = {
        method: method,
        headers: headers
    };

    if (method !== 'GET' && postData) {
		console.log("postData=" + JSON.stringify(postData));

        // Handle different postData types
        if (typeof postData === 'string') {
            // Only add body if the string is not empty
            if (postData.trim()) {
                options.body = postData;
            }
        } else if (typeof postData === 'object') {
            // Handle objects by converting to JSON string
            options.body = JSON.stringify(postData);
            // Ensure content-type is application/json if not already set
            if (!options.headers['Content-Type'] && !options.headers['content-type']) {
                options.headers['Content-Type'] = 'application/json';
            }
        }
    }

    // Handle Business Central APIs with MSAL authentication
    if (apiUrl.includes('businesscentral.dynamics.com')) {
        try {
            const token = await getToken();

            if (token) {
                options.headers['Authorization'] = `Bearer ${token}`;

				requestInfo += `Authentication: Using MSAL (token first 10 chars: ${token.substring(0, 10)}...)\n`;
            }
            options.headers['OData-MaxVersion'] = '4.0';
            options.headers['OData-Version'] = '4.0';
            options.headers['If-None-Match'] = '*';
            options.headers['Prefer'] = 'odata.include-annotations="*"';
        } catch (authError) {
            return {
                success: false,
                status: "auth_error",
                message: `Authentication Error: ${authError.message}`,
                data: null,
                requestInfo: requestInfo,
                timestamp: timestamp
            };
        }
    }

	requestInfo += `URL: ${apiUrl}\n`;
	requestInfo += `Method: ${method}\n`;
	requestInfo += `Headers:\n${JSON.stringify(options.headers, null, 2)}\n`;

	// Add body information to requestInfo if it exists
	if (options.body) {
		requestInfo += `Body:\n${options.body}\n`;
	}

    let responseObj = {
        success: false,
        status: "",
        message: "",
        data: null,
        requestInfo: requestInfo,
        timestamp: timestamp
    };

    try {
		//log("postData as object:");
		//log(postData);
		log("postData as stringify:");
		log(JSON.stringify(postData));
		//log("headers as object")
		//log(options.headers);
		log("headers as stringify")
		log(JSON.stringify(options.headers));

        const response = await fetch(apiUrl, options); // <--------- ACTUAL WORK

        if (method === 'PATCH' && (apiUrl.includes('contacts') || verbose)) {
            console.log('🔍 CONTACT UPDATE DEBUG - fetch response received');
            console.log('🔍 Response status:', response.status, 'statusText:', response.statusText, 'ok:', response.ok);
            console.log('🔍 Response headers:', Object.fromEntries(response.headers.entries()));
        }

		const text = await response.text();

        if (method === 'PATCH' && (apiUrl.includes('contacts') || verbose)) {
            console.log('🔍 CONTACT UPDATE DEBUG - response text received');
            console.log('🔍 Response text length:', text.length);
            console.log('🔍 Response text preview:', text.substring(0, 200));
        }

        // Add HTTP status information
        responseObj.status = response.status;
        responseObj.statusText = response.statusText;

        // If response was successful, save this URL in history
        if (response.ok) {
            // For POST, pass the actual postData. For GET, leave it null
            responseObj.success = true;

                if (method === 'PATCH' && (apiUrl.includes('contacts') || verbose)) {
                console.log('🔍 CONTACT UPDATE DEBUG - SUCCESS response');
                console.log('✅ Contact update appears successful');
            }

            if (method === 'POST' && (apiUrl.includes('flow') || (postData && postData.action && (postData.action === 'add' || postData.action === 'remove')))) {
                console.log('🔍 WEB ROLE FLOW DEBUG - SUCCESS response');
                console.log('✅ Web role flow call appears successful');
                console.log('✅ Action completed:', postData.action, 'for role:', postData.roleId);
            }
        } else {
                if (method === 'PATCH' && (apiUrl.includes('contacts') || verbose)) {
                console.log('🔍 CONTACT UPDATE DEBUG - FAILED response');
                console.error('❌ Contact update failed with status:', response.status, response.statusText);
            }

            if (method === 'POST' && (apiUrl.includes('flow') || (postData && postData.action && (postData.action === 'add' || postData.action === 'remove')))) {
                console.log('🔍 WEB ROLE FLOW DEBUG - FAILED response');
                console.error('❌ Web role flow call failed with status:', response.status, response.statusText);
                console.error('❌ Failed action:', postData.action, 'for role:', postData.roleId);
            }
        }

        try {
            // Try to parse as JSON
            const json = JSON.parse(text);
            responseObj.data = json;
            responseObj.message = "JSON response received";
        } catch (e) {
            // If not JSON, store the raw text in a structured way
            responseObj.data = { rawText: text };
            responseObj.message = "Non-JSON response received and wrapped";
        }

        log(JSON.stringify(responseObj, null, 2));
    } catch (error) {
        responseObj.status = "fetch_error";
        responseObj.message = `Network Error: ${error.message}`;
        console.error(responseObj.message);

        if (method === 'PATCH' && apiUrl.includes('contacts')) {
            console.error('🔍 CONTACT UPDATE DEBUG - NETWORK ERROR');
            console.error('❌ Contact update network error:', error);
            console.error('❌ Error details:', {
                name: error.name,
                message: error.message,
                stack: error.stack
            });
        }

        if (method === 'POST' && (apiUrl.includes('flow') || (postData && postData.action))) {
            console.error('🔍 WEB ROLE FLOW DEBUG - NETWORK ERROR');
            console.error('❌ Web role flow network error:', error);
            console.error('❌ Error details:', {
                name: error.name,
                message: error.message,
                stack: error.stack,
                action: postData.action,
                roleId: postData.roleId
            });
        }
    } finally {
        log("---");
    }

    return responseObj;
}

