// #region JQuery and Bootstrap (so we can test a page without deploying)
function loadScript(url, callback) { // Load a script dynamically, used for local dev to load jQuery
	const script = document.createElement('script');
	script.src = url;
	script.onload = callback;
	document.head.appendChild(script);
}

function loadStylesheet(url) { // Load stylesheet dynamically, used for local dev to load bootstrap
	const link = document.createElement('link');
	link.rel = 'stylesheet';
	link.href = url;
	document.head.appendChild(link);
}

// Return a promise from loadJqueryAndBootstrap
function loadJqueryAndBootstrap() {
    return new Promise((resolve) => {
        if (typeof jQuery === 'undefined') {
            console.log('jQuery not detected, loading from CDN');
            loadScript('https://cdnjs.cloudflare.com/ajax/libs/jquery/3.7.1/jquery.min.js', function() {
                console.log('jQuery loaded successfully');
                checkAndLoadBootstrap(resolve);
            });
        } else {
            console.log('jQuery already available');
            checkAndLoadBootstrap(resolve);
        }
    });
}

// Pass the resolve function to checkAndLoadBootstrap
function checkAndLoadBootstrap(resolve) {
    if (typeof bootstrap === 'undefined') {
        console.log('Bootstrap not detected, loading from CDN');

        // Load Bootstrap CSS
        loadStylesheet('https://cdnjs.cloudflare.com/ajax/libs/bootstrap/5.3.2/css/bootstrap.min.css');

        // Load Bootstrap JS (which requires jQuery)
        loadScript('https://cdnjs.cloudflare.com/ajax/libs/bootstrap/5.3.2/js/bootstrap.bundle.min.js', function() {
            console.log('Bootstrap loaded successfully');
            resolve(); // Resolve the promise when Bootstrap is loaded
        });
    } else {
        console.log('Bootstrap already available');
        resolve(); // Resolve the promise immediately if Bootstrap is already available
    }
}
