/**
 * Returns a relative time description at the minute level for a target date compared to a reference date
 * See daysAgo for a more granular (day level) version
 * @param {string|Date} targetDate - The date to compare
 * @param {string|Date|null} referenceDate - The reference date (defaults to current time)
 * @returns {string} - "just now", "X mins ago", "X hours ago", "yesterday", or "X days ago"
 */
function minutesAgo(targetDate, referenceDate = null) {
    // Convert inputs to Date objects if they aren't already
    const target = new Date(targetDate);
    const reference = referenceDate ? new Date(referenceDate) : new Date();

    // Calculate the difference in milliseconds
    const diffMs = reference - target;
    const diffMinutes = Math.floor(diffMs / (1000 * 60));
    const diffHours = Math.floor(diffMs / (1000 * 60 * 60));
    const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));

    if (diffMinutes < 1) {
        return "just now";
    } else if (diffMinutes < 60) {
        return `${diffMinutes} mins ago`;
    } else if (diffHours < 24) {
        return `${diffHours} hours ago`;
    } else if (diffDays === 1) {
        return "yesterday";
    } else if (diffDays > 1) {
        return `${diffDays} days ago`;
    } else {
        // Future date
        return "just now";
    }
}

