// #region Controls
function isChecked(checkboxId) {
	const selector = checkboxId.BeginsWith("#") ? checkBoxId : "#" + checkboxId;

	return $(selector).is(":checked");
}

// #region select element

/**
 * Gets the selected option's value and text from a select element
 * @param {string} id - The ID of the select element (with or without "#")
 * @returns {Object} An object containing the value and text of the selected option
 */
 function getSelectSelected(id) {
  try {
    const selectId = id.startsWith("#") ? id : `#${id}`;

    const eSel = document.querySelector(selectId);

    // Check if the element exists and is a select element
    if (!eSel || eSel.tagName !== 'SELECT') {
      throw new Error(`Element with ID ${id} is not a valid select element`);
    }

    // Get the selected option
    const opt = eSel.options[eSel.selectedIndex];

    // Check if we have a valid selected option
    if (!opt) {
      throw new Error(`No option selected in select element with ID ${id}`);
    }

    return {
      value: String(opt.value),
      text: String(opt.textContent)
    };
  } catch (error) {
    console.error(`Error getting selected option for ${id}:`, error);

    // Return error values
    return {
      value: "error",
      text: "error"
    };
  }
}

// #endregion select element

function initPersistentControls() {
	// Class to identify form elements that should be persisted to local storage, meaning their values will be restored on form reload
	const PERSIST_CLASS = 'rj-persist';

	// Load saved values when page loads
	$('.' + PERSIST_CLASS).each(function() {
		const elemId = $(this).attr('id');
		if (!elemId) {
			const outerHtml = $(this).prop('outerHTML');
    		console.warn("Element has class " + PERSIST_CLASS + ", but has no id. outerHTML=", outerHtml.length > 100 ? outerHtml.substring(0, 100) + '...' : outerHtml);
			return;
		}

		restoreElementValue(elemId);
	});

	// Save values when changed
	$(document).on('change input', '.' + PERSIST_CLASS, function() {
		const elemId = $(this).attr('id');
		if (!elemId) return;

		const elemType = $(this).attr('type') || this.tagName.toLowerCase();
		let valueToStore;

		switch(elemType) {
			case 'checkbox':
				valueToStore = $(this).prop('checked');
				break;
			case 'radio':
				// Only save radio value when checked
				if (!$(this).prop('checked')) return;
				valueToStore = $(this).val();
				break;
			case 'select':
				valueToStore = $(this).val();
				console.log(valueToStore + " tag=3151017a"); // for example, useful for a dropdown of contactid, so as to be able to copy it
				break;
			case 'select':
				valueToStore = $(this).val();
				console.log(valueToStore + " tag=3151017b"); // for example, useful for a dropdown of contactid, so as to be able to copy it
				break;
			default:
				valueToStore = $(this).val();
				break;
		}

		localStorage.setItem('input_' + elemId, valueToStore);
	});
} // initPersistentControls

function restoreElementValue(elemId, debug = false) {
    const $elem = $('#' + elemId);

	if (debug)
		console.log("ENTER: restoreElementValue: elemId=" + elemId);

    if (!$elem.length) {
        console.warn(`Element with id ${elemId} not found`);
        return false;
    }

    const savedValue = localStorage.getItem('input_' + elemId);

    if (savedValue === null) {		
		if (debug)
			console.log("restoreElementValue: leaving early cuz savedValue as retrieved from localStorage is null");

		return false;
	}

    const elemType = $elem.attr('type') || $elem[0].tagName.toLowerCase();

    switch(elemType) {
        case 'checkbox':
            $elem.prop('checked', savedValue === 'true');

			if (debug)
				console.log("restoreElementValue: called $elem.prop('checked') with " + savedValue);

            break;
        case 'radio':
            if ($elem.val() === savedValue) {
                $elem.prop('checked', true);

				if (debug)
					console.log("restoreElementValue: radio: DID get set to checked, because elem.val === savedValue, where savedValue=" + savedValue);
            } else {
				if (debug)
					console.log("restoreElementValue: radio: did NOT set, because it is not true the elem.val === savedValue, where savedValue=" + savedValue);
			}
            break;
        case 'select':
        case 'textarea':
        case 'text':
        case 'number':
        case 'email':
        case 'password':
        case 'tel':
        case 'url':
        case 'date':
        case 'time':
        case 'color':
        default:
            $elem.val(savedValue);

			if (debug)
				console.log("restoreElementValue: we did call $elem.val(savedValue), where savedValue=" + savedValue);

            break;
    }
}

