// Helper function to check if debug tags should trigger logging
function shouldDebugLog(tags) {
	if (!tags || tags.trim() === "")
		return false;

	// Split CSV tags and trim whitespace from each token
	const tokens = tags.split(',').map(token => token.trim()).filter(token => token !== "");

	// Check if any token matches G_Tags or if "all" is present
	// G_Tags can be set from query string parameter -OR- localStorage key 'tags' - see IIFE in global javascript, currently in Footer
	return tokens.some(token => window.G_Tags.Has(token)) || window.G_Tags.Has("all");
}

function dbglog(msg, tags = "") {
	if (shouldDebugLog(tags)) {
		console.log(msg);
	}
}

function dbgerr(msg, tags = "") {
	if (shouldDebugLog(tags)) {
		console.error(msg);
	}
}

function dbgwarn(msg, tags = "") {
	if (shouldDebugLog(tags)) {
		console.warn(msg);
	}
}

/**
 * Extracts properties from an object that match a given regex pattern.
 * 
 * Typical use case: suppose you query Dataverse and have a record. But you only want the lv_
 * columns
 * 
 * If no pattern is provided, returns a copy of the original object.
 * 
 * @param {Object} obj - The source object to extract properties from
 * @param {string|RegExp} [pattern] - Optional regex pattern to match property names
 * @returns {Object} A new object containing the matching properties (or all properties if no pattern)
 */
 function ExtractProperties(obj, pattern) {
	if (IsEmpty(pattern)) {
		return { ...obj }; // shallow copy
	}

	const regex = typeof pattern === 'string' ? new RegExp(pattern) : pattern;

	const result = {};

	for (const propName in obj) {
		if (obj.hasOwnProperty(propName) && regex.test(propName)) {
			result[propName] = obj[propName];
		}
	}

	return result;
}

/**
 * Filters an array of objects, keeping only properties that match the regex pattern
 * @param {Array<Object>} arrayOfObjects - Array of objects to filter
 * @param {string|RegExp} pattern - Regex pattern for property names to keep
 * @returns {Array<Object>} New array with filtered objects
 */
 function ExtractPropertiesFromArray(arrayOfObjects, pattern) { // returns a new array created from arrayOfObjects
	if (!Array.isArray(arrayOfObjects) || arrayOfObjects.length === 0) {
		return [];
	}

	return arrayOfObjects.map(obj => ExtractProperties(obj, pattern));
}

function delay(msecs = 1) {

	if (msecs < 10)
		msecs = 1000 * msecs;

  return new Promise(resolve => setTimeout(resolve, msecs));
}

function safeStringToNumeric(currencyString) {
  let sign = 1;
  if (currencyString.startsWith('-')) {
    sign = -1;
    currencyString = currencyString.substring(1); // Remove the leading minus sign
  }

  // Remove dollar signs, commas, and any other non-numeric characters
  // The regex `/[^0-9.]/g` matches any character that is NOT a digit (0-9) or a literal dot.
  // This assumes the decimal separator is always a dot.
  const cleanedString = currencyString.replace(/[^0-9.]/g, '');

  // Parse the cleaned string to a float
  const numericValue = parseFloat(cleanedString);

  // Should it instead just return NaN
  if (isNaN(numericValue)) {
    return 0.0; // Or throw an error?
  }

  return numericValue * sign;
}

